    <script>
        document.addEventListener('DOMContentLoaded', () => {
            const triggerQuickReply = (text) => {
                if (!text || ['…', '...'].includes(text.trim()) || text.trim().length === 0) return;
                if (typeof triggerSlash === 'function') {
                    triggerSlash(`/send ${text}|/trigger`);
                } else {
                    console.log('SillyTavern [DEV]:', text);
                }
            };

            initThemeToggle();
            const storyRenderer = new StoryRenderer('yaml-data-source');
            storyRenderer.init();

            document.getElementById('options-container').addEventListener('click', (e) => {
                const optionItem = e.target.closest('li');
                if (optionItem && optionItem.parentElement.id === 'options-list') {
                    const optionText = optionItem.getAttribute('data-full-text') || optionItem.textContent.trim();
                    triggerQuickReply(optionText);
                    const originalBg = optionItem.style.backgroundColor;
                    optionItem.style.backgroundColor = 'rgba(157, 124, 245, 0.2)';
                    setTimeout(() => { optionItem.style.backgroundColor = originalBg; }, 300);
                }
            });
        });

        function initThemeToggle() {
            const themeButtons = document.querySelectorAll('.theme-btn');
            const bodyElement = document.body;
            const savedTheme = localStorage.getItem('storyTheme') || 'night';
            switchToTheme(savedTheme);
            themeButtons.forEach(button => {
                button.addEventListener('click', () => {
                    const theme = button.getAttribute('data-theme');
                    switchToTheme(theme);
                    localStorage.setItem('storyTheme', theme);
                });
            });
            function switchToTheme(theme) {
                bodyElement.className = '';
                bodyElement.classList.add(`${theme}-mode`, 'theme-transition');
                themeButtons.forEach(btn => {
                    btn.classList.toggle('active', btn.getAttribute('data-theme') === theme);
                });
            }
        }

        class StoryRenderer {
             constructor(dataSourceId) {
                this.dataSourceId = dataSourceId;
                this.yamlData = null;
                this.rawYamlContent = "";
                this.rootNode = null;
                this.initElements();
            }

            initElements() {
                this.elements = {
                    timeDisplay: document.getElementById('time-display'),
                    locationDisplay: document.getElementById('location-display'),
                    charactersContainer: document.getElementById('characters-container'),
                    actionOwner: document.getElementById('action-owner'),
                    optionsList: document.getElementById('options-list')
                };
            }

            init() {
                try {
                    this.loadYamlFromScriptTag();
                    this.findRootNode();
                    this.renderAll();
                    this.setupEventListeners();
                } catch (error) { this.handleError(error); }
            }

            loadYamlFromScriptTag() {
                const scriptElement = document.getElementById(this.dataSourceId);
                if (!scriptElement) throw new Error('Không tìm thấy nguồn dữ liệu YAML');
                this.rawYamlContent = scriptElement.textContent.trim();
                if (!this.rawYamlContent) throw new Error('Nội dung YAML trống');
                try { this.yamlData = jsyaml.load(this.rawYamlContent); }
                catch (e) { throw new Error(`Lỗi phân tích YAML: ${e.message}`); }
            }

            extractEmojis(text) { return text.match(/[\u{1F600}-\u{1F64F}\u{1F300}-\u{1F5FF}\u{1F680}-\u{1F6FF}\u{1F1E0}-\u{1F1FF}\u{2600}-\u{26FF}\u{2700}-\u{27BF}]/gu) || []; }

            getEmojiForField(fieldName) {
                const lines = this.rawYamlContent.split('\n');
                const fieldNameClean = fieldName.replace(/[\u{1F300}-\u{1F5FF}]/gu, '').trim();
                for (const line of lines) {
                    if (line.includes(fieldNameClean) && line.includes(':')) {
                        const emojis = this.extractEmojis(line);
                        if (emojis.length > 0) return emojis[0];
                    }
                }
                return '🔸';
            }

            findRootNode() { this.rootNode = Object.keys(this.yamlData)[0]; }

            renderAll() {
                const rootData = this.yamlData[this.rootNode];
                if (!rootData) return;
                this.renderHeaderInfo(rootData);
                this.renderCharacters(rootData);
                this.renderActionOptions(rootData);
            }

            renderHeaderInfo(rootData) {
                const dateTimeField = this.findFieldByKeywords(rootData, ['Thời gian']);
                const locationField = this.findFieldByKeywords(rootData, ['Địa điểm']);
                const timeDisplay = this.elements.timeDisplay;
                const locationDisplay = this.elements.locationDisplay;

                if (dateTimeField && rootData[dateTimeField]) {
                    timeDisplay.textContent = rootData[dateTimeField].replace(/[^\p{L}\p{N}\s:午]/gu, '');
                    timeDisplay.parentNode.querySelector('.emoji').textContent = this.getEmojiForField(dateTimeField);
                }
                if (locationField && rootData[locationField]) {
                    locationDisplay.textContent = rootData[locationField].replace(/[^\p{L}\p{N}\s:]/gu, '');
                    locationDisplay.parentNode.querySelector('.emoji').textContent = this.getEmojiForField(locationField);
                }
            }

            findFieldByKeywords(data, keywords) {
                if (!data || typeof data !== 'object') return null;
                const fields = Object.keys(data);
                for (const field of fields) {
                    for (const keyword of keywords) {
                        if (field.includes(keyword)) return field;
                    }
                }
                return null;
            }

            renderCharacters(rootData) {
                const userListField = this.findFieldByKeywords(rootData, ['Gặp gỡ', 'Nhân vật']);
                const userList = (userListField && Array.isArray(rootData[userListField])) ? rootData[userListField] : [];
                this.elements.charactersContainer.innerHTML = '';
                if (userList.length === 0) {
                    this.elements.charactersContainer.innerHTML = this.createEmptyState('Ở đây chưa có ai cả');
                    return;
                }
                userList.forEach(userItem => {
                    const userDataField = this.findFieldByKeywords(userItem, ['Nhân vật xuất hiện']);
                    if (userDataField) {
                        const characterCard = this.createCharacterCard(userItem[userDataField]);
                        if (characterCard) this.elements.charactersContainer.appendChild(characterCard);
                    }
                });
            }

            createCharacterCard(userData) {
                if (!userData) return null;
                const card = document.createElement('div');
                card.className = 'rounded-xl border p-3.5 shadow-sm card-hover character-card theme-transition';

                const nameField = this.findFieldByKeywords(userData, ['Tên']);
                const userName = nameField ? userData[nameField] : 'Nhân vật bí ẩn';
                const nameEmojis = this.extractEmojis(userName);
                const cleanName = userName.replace(/[\u{1F000}-\u{1FFFF}]/gu, '').trim();

                const title = document.createElement('h3');
                title.className = 'font-bold text-lg mb-2 pb-1 border-b theme-transition';
                title.innerHTML = `${nameEmojis.join(' ')} ${cleanName}`;
                card.appendChild(title);

                const attributesList = document.createElement('ul');
                attributesList.className = 'space-y-2 text-sm';
                card.appendChild(attributesList);

                Object.keys(userData).forEach(key => {
                    if (key !== nameField) {
                        const attributeItem = this.createAttributeItem(key, userData[key]);
                        if (attributeItem) attributesList.appendChild(attributeItem);
                    }
                });
                return card;
            }

            createAttributeItem(key, value) {
                if (!value) return null;
                const item = document.createElement('li');
                const emoji = this.getEmojiForField(key);
                const valueText = value.toString().replace(/[\u{1F000}-\u{1FFFF}]/gu, '').trim();

                if (key.includes("Bí mật")) {
                    item.className = 'italic p-2 rounded-lg border-l-4 theme-transition secret-thought';
                    item.innerHTML = `<span class="opacity-70">${emoji} ${key}: ${valueText}</span>`;
                } else {
                    item.innerHTML = `<span class="font-semibold text-primary/80">${emoji} ${key}:</span> ${valueText}`;
                }
                return item;
            }


            renderActionOptions(rootData) {
                const actionOptionsField = this.findFieldByKeywords(rootData, ['Muốn chơi', 'Chơi gì']);
                const actionOptions = actionOptionsField ? rootData[actionOptionsField] : {};
                const ownerField = this.findFieldByKeywords(actionOptions, ['Tên']);
                const ownerName = ownerField ? actionOptions[ownerField] : 'Bạn';
                const cleanOwnerName = ownerName.replace(/[\u{1F000}-\u{1FFFF}]/gu, '').trim();
                this.elements.actionOwner.innerHTML = `${this.extractEmojis(ownerName).join(' ')} ${cleanOwnerName}`;

                const optionsField = this.findFieldByKeywords(actionOptions, ['Lựa chọn']);
                const options = (optionsField && Array.isArray(actionOptions[optionsField])) ? actionOptions[optionsField] : [];
                this.elements.optionsList.innerHTML = '';

                if (options.length === 0) {
                    this.elements.optionsList.innerHTML = this.createEmptyState('Không có gì để chơi cả...');
                    return;
                }

                options.forEach(optionText => {
                    const fullText = optionText.trim();
                    const cleanOptionText = fullText.replace(/\[.*?\]/g, '').trim();
                    const categoryMatch = fullText.match(/\[(.*?)\]/);
                    const category = categoryMatch ? categoryMatch[1].replace(/[？?]/g, '') : '';

                    const optionItem = document.createElement('li');
                    optionItem.className = 'pl-2 py-1.5 border-l-2 ml-1 hover:border-opacity-70 transition-colors flex items-start gap-2 theme-transition';
                    optionItem.setAttribute('data-full-text', fullText);

                    const categoryHTML = category ? `<span class="text-xs bg-primary/20 text-primary px-1.5 py-0.5 rounded-full whitespace-nowrap">${category}</span>` : '';
                    optionItem.innerHTML = `<span class="flex-shrink-0">▸</span><div class="flex-grow">${cleanOptionText}</div>${categoryHTML}`;
                    this.elements.optionsList.appendChild(optionItem);
});
            }

            createEmptyState(message) { return `<div class="text-center py-4 opacity-60"><i class="fa fa-info-circle mr-1"></i>${message}</div>`; }

            setupEventListeners() {
                const detailsElement = document.querySelector('details');
                const contentElement = this.elements.charactersContainer;
                contentElement.style.maxHeight = '0';
                detailsElement.addEventListener('toggle', () => {
                    contentElement.style.maxHeight = detailsElement.open ? `${contentElement.scrollHeight}px` : '0';
                });
                detailsElement.open = true;
            }

            handleError(error) {
                console.error('Lỗi hiển thị:', error);
                const container = this.elements.charactersContainer || document.body;
                container.innerHTML = `<div class="bg-red-900/20 border border-red-800/30 text-red-400 px-4 py-3 rounded"><strong class="font-bold">Tải thất bại: </strong><span>${error.message}</span></div>`;
            }
        }
    </script>
